<?phpnamespace app\dep\Web;use app\model\Web\MusicModel;use app\enum\CommonEnum;class MusicDep{    public $model;    public function __construct()    {        $this->model = new MusicModel();    }    public function first($id)    {        $res = $this->model->where('id', $id)->first();        return $res;    }    public function firstByPlatform($platform)    {        $res = $this->model->where('platform', $platform)->where('is_del', CommonEnum::NO)->first();        return $res;    }    public function firstByPlatformId($id)    {        $res = $this->model->where('platform_id', $id)->where('is_del', CommonEnum::NO)->first();        return $res;    }    public function firstBySuperAdmin()    {        $res = $this->model->where('name', '超级管理员')->where('is_del', CommonEnum::NO)->first();        return $res;    }    public function firstByAdmin()    {        $res = $this->model->where('name', '管理员')->where('is_del', CommonEnum::NO)->first();        return $res;    }     public function firstByNameAndArtist($name, $artist)    {        $res = $this->model->where('name', $name)->where('artist', $artist)->where('is_del', CommonEnum::NO)->first();        return $res;    }    public function getUserByToken($token)    {        $res = $this->model->where('token', $token)->first();        return $res;    }    public function firstByEmail($email){        $res = $this->model->where('email',$email)->first();        return $res;    }    public function firstByToken($token){        $res = $this->model->where('token',$token)->first();        return $res;    }    public function all()    {        $res = $this->model->all();        return $res;    }    public function allOK()    {        $res = $this->model->where('is_del', CommonEnum::NO)->get();        return $res;    }    public function add($data)    {        $res = $this->model->insertGetId($data);        return $res;    }    public function edit($id, $data)    {        if(!is_array($id)){            $id = [$id];        }        $res = $this->model->whereIn('id', $id)->update($data);        return $res;    }    public function batchEdit($ids, $data)    {        $res = $this->model->whereIn('id', $ids)->update($data);        return $res;    }    public function del($id, $data)    {        if(!is_array($id)){            $id = [$id];        }        $res = $this->model->whereIn('id', $id)->update($data);        return $res;    }    public function list($param){        $res = $this->model            ->where('is_del', CommonEnum::NO)            ->when(!empty($param['name']), function ($query) use ($param) {                $query->where('name','like' ,"%{$param['name']}%");            })            ->when(!empty($param['artist']), function ($query) use ($param) {                $query->where('artist','like' ,"%{$param['artist']}%");            })            ->orderBy('id','desc')            ->paginate($param['page_size'], ['*'], 'page', $param['current_page']);        return $res;    }}